
import torch
from torch.fft import fft, ifft

# consider the following join:
#   X.1 = Y.2 AND Y.3 = Z.4
#
# Let X, Y, and Z be the following tables containing a single element:
# X [4] --- Y [4, 1] --- Z [1]
# thus the actual join size is 1
print("Actual join size is 1")

# Sketching dimensions are [depth 5, width 10]

depth = 5
width = 10

# We require 2 hash functions and 2 xi functions, given below:

# h1 and h2 are pairwise independent
h1_X1 = h1_Y2 = torch.tensor([3, 2, 3, 2, 3]).unsqueeze(-1)
h2_Z4 = h2_Y3 = torch.tensor([7, 2, 6, 4, 0]).unsqueeze(-1)

# xi1 and xi2 are 4-wise independent
xi1_X1 = xi1_Y2 = torch.tensor([-1, 1, 1, 1, 1]).unsqueeze(-1)
xi2_Z4 = xi2_Y3 = torch.tensor([-1, 1, -1, 1, 1]).unsqueeze(-1)


# First, the prior Convolution and Cross-Correlation method (Heddes et al., SIGMOD'24)
#
# X1 and Z4 are sketched by the own respective hash functions
# Y is sketched by both hash functions

X1 = torch.zeros((depth, width), dtype=torch.long)\
    .scatter_add(1, h1_X1, xi1_X1)

Z4 = torch.zeros((depth, width), dtype=torch.long)\
    .scatter_add(1, h2_Z4, xi2_Z4)

# circular convolution of h1 and h2
Y = torch.zeros((depth, width), dtype=torch.long)\
    .scatter_add(1, (h1_Y2 + h2_Y3) % width, xi1_Y2 * xi2_Y3)

# estimation:
# fft(Y) must be conjugated
# the product of this conjugate with X1 and Z4 cancels out the convolution
prod = ifft(fft(X1) * fft(Y).conj() * fft(Z4)).real
prod = ifft(fft(X1).conj() * fft(Y)).real * Z4
est = prod.sum(dim=-1)

print("[w/ conjugated count sketch] The independent estimates are:")
print(est)

# Now, the new Complement Count Sketches (Anonymous, PODS'25)
#
# The complement count sketch of Y "flips" h1 and h2

flipped_h1_Y2 = width - h1_Y2 - 1
flipped_h2_Y3 = width - h2_Y3 - 1

Y_complement = torch.zeros((depth, width), dtype=torch.long)\
                .scatter_add(1, (flipped_h1_Y2 + h2_Y3) % width, xi1_Y2 * xi2_Z4)

Z_complement = torch.zeros((depth, width), dtype=torch.long)\
                .scatter_add(1, (width - h2_Z4 - 1), xi2_Z4)

# estimation:
# we no longer conjugate

prod = ifft(fft(X1) * fft(Y_complement) * fft(Z4)).real
prod = ifft(fft(X1) * fft(Y_complement) * fft(Z_complement)).real
est = prod.sum(dim=-1)

print("[w/ complement count sketch] The independent estimates are:")
print(est)














